def write_member(m):
    data = {
        "slug": m["slug"],
        "nom": m["nom"],
        "prenom": m["prenom"],
        "civilite": m["civilite"],
        "researched_at": "2026-04-01",
        "_ingested": False,
        "sources_used": m["sources_used"],
        "notes": m["notes"],
        "career_entries": [
            {**e, "_ingested": False} if "_ingested" not in e else e
            for e in m["career_entries"]
        ],
        "judicial_events": [
            {**e, "_ingested": False} if "_ingested" not in e else e
            for e in m["judicial_events"]
        ]
    }
    path = os.path.join(OUTPUT_DIR, f"{m['slug']}.json")
    with open(path, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    return m["slug"]

if __name__ == "__main__":
    created = 0
    skipped = 0
    for m in MEMBERS:
        path = os.path.join(OUTPUT_DIR, f"{m['slug']}.json")
        if os.path.exists(path):
            skipped += 1
            continue
        slug = write_member(m)
        created += 1
        jud = len(m["judicial_events"])
        print(f"  {slug} ({len(m['career_entries'])} career, {jud} judicial)")
    print(f"\nDone: {created} created, {skipped} skipped (already exist)")
